+        );
+    }
+}
+
+impl<T: Clone + Send + Sync> Drop for LeftRightReader<'_, T> {
+    fn drop(&mut self) {
+        self.slot.store(SLOT_IDLE, Ordering::Release);
+        self.lock.unregister_reader(self.registry_index, &self.slot);
+    }
+}
