+#[inline]
+fn inactive_side(side: usize) -> usize {
+    side ^ 1
+}
+
+#[inline]
+fn encode_side(side: usize) -> u8 {
+    debug_assert!(side < SIDE_COUNT);
+    side as u8 + 1
+}
